// Constants
const AUTH_URL = 'YOUR_AUTH_URL';
const TOKEN_URL = 'YOUR_TOKEN_URL';

// Function to initiate OAuth authorization
function oauthAuthorize() {
  const authUrl = `${AUTH_URL}?client_id=YOUR_CLIENT_ID&redirect_uri=YOUR_REDIRECT_URI&response_type=code`;
  window.location.href = authUrl;
}

// Function to exchange authorization code for access token
async function oauthToken(code) {
  const data = {
    client_id: 'YOUR_CLIENT_ID',
    client_secret: 'YOUR_CLIENT_SECRET',
    redirect_uri: 'YOUR_REDIRECT_URI',
    grant_type: 'authorization_code',
    code: code,
  };

  const response = await fetch(TOKEN_URL, {
    method: 'POST',
    body: JSON.stringify(data),
    headers: {
      'Content-Type': 'application/json',
    },
  });

  const json = await response.json();
  return json.access_token;
}

// Function to make API requests with access token
async function apiRequest(url, accessToken) {
  const response = await fetch(url, {
    headers: {
      Authorization: `Bearer ${accessToken}`,
    },
  });

  return await response.json();
}

// Event listener for redirect with authorization code
window.addEventListener('load', () => {
  const url = window.location.href;
  const code = new URLSearchParams(url).get('code');

  if (code) {
    oauthToken(code).then((accessToken) => {
      localStorage.setItem('accessToken', accessToken);
      // Redirect to the desired page after successful authentication
      window.location.href = '/';
    });
  }
});

